schema:
type Group implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    description: String
}

type Tag implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    color: String!
}

extend type Query {
    tag(id: ID! @idOf(type: "Tag")): Tag @resolver
}

type GroupMember implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    userId: String!
    role: String!
}

type Tag implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
}

type Group implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    tags: [Tag!]! @resolver
}

type Tag implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    color: String!
}

input CreateTagInput {
    name: String!
    color: String!
}

input UpdateTagInput {
    id: ID! @idOf(type: "Tag")
    name: String
    color: String
}

extend type Mutation {
    createTag(input: CreateTagInput!): Tag! @resolver
    updateTag(input: UpdateTagInput!): Tag @resolver
    deleteTag(id: ID! @idOf(type: "Tag")): Boolean! @resolver
}

type Tag implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
}

type User implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    email: String!
}

type Tag implements Node @resolver @scope(to: ["default"]) {
    id: ID!
    name: String!
    createdById: String!
    createdBy: User @resolver
}
